const events = $input.all();
const yesterday = new Date();
yesterday.setDate(yesterday.getDate() - 1);
yesterday.setHours(0, 0, 0, 0);

const validEvents = events.filter(item => {
  const data = item.json;
  const eventDate = new Date(data.event_date);

  // Only analyze if:
  // 1. Event was yesterday or earlier
  // 2. Has Facebook Event ID
  // 3. Was actually posted
  return eventDate <= yesterday &&
         data.facebook_event_id &&
         data.facebook_event_id !== '' &&
         (data.status === 'Promoted on Facebook' || 
          data.status === 'Promoted on Facebook + Instagram');
});

return validEvents.map(item => item.json);

const eventData = $node["Process Each Event"].json;
const fbEventStats = $node["Fetch Final Event Metrics"]?.json || {};
const fbPostStats = $node["Fetch Post Engagement"]?.json || {};
const igStats = $node["Fetch Instagram Performance"]?.json || {};
const salesData = $node["Fetch Ticket Sales Data"]?.json || {};

// Facebook Event Metrics
const totalRSVPs = (fbEventStats.attending_count || 0) + 
                   (fbEventStats.interested_count || 0) + 
                   (fbEventStats.maybe_count || 0);
const rsvpConversionRate = totalRSVPs > 0 ? 
  parseFloat(((fbEventStats.attending_count || 0) / totalRSVPs * 100).toFixed(2)) : 0;

// Facebook Post Metrics
const postInsights = fbPostStats.insights?.data || [];
const impressions = postInsights.find(m => m.name === 'post_impressions')?.values?.[0]?.value || 0;
const engagedUsers = postInsights.find(m => m.name === 'post_engaged_users')?.values?.[0]?.value || 0;

const totalReactions = fbPostStats.reactions?.summary?.total_count || 0;
const totalShares = fbPostStats.shares?.count || 0;
const totalComments = fbPostStats.comments?.summary?.total_count || 0;
const totalEngagement = totalReactions + totalShares + totalComments;

const engagementRate = impressions > 0 ? 
  parseFloat(((totalEngagement / impressions) * 100).toFixed(2)) : 0;

// Instagram Metrics (if available)
const igMetrics = igStats.data || [];
const igImpressions = igMetrics.find(m => m.name === 'impressions')?.values?.[0]?.value || 0;
const igEngagement = igMetrics.find(m => m.name === 'engagement')?.values?.[0]?.value || 0;
const igSaves = igMetrics.find(m => m.name === 'saves')?.values?.[0]?.value || 0;

// Ticket Sales Attribution
const ticketsSold = salesData.total_sold || salesData.tickets_sold || 0;
const revenue = salesData.total_revenue || salesData.revenue || 0;
const avgTicketPrice = ticketsSold > 0 ? parseFloat((revenue / ticketsSold).toFixed(2)) : 0;

// Calculate social attribution (% of sales from social)
const socialReferrals = salesData.referral_sources?.facebook || salesData.facebook_referrals || 0;
const socialAttribution = ticketsSold > 0 ? 
  parseFloat(((socialReferrals / ticketsSold) * 100).toFixed(2)) : 0;

// ROI Calculation
const promotionCost = eventData.promotion_budget || 0;
const socialRevenue = parseFloat((revenue * (socialAttribution / 100)).toFixed(2));
const roi = promotionCost > 0 ? 
  parseFloat((((socialRevenue - promotionCost) / promotionCost) * 100).toFixed(2)) : 0;

// Overall Performance Score (1-100)
let performanceScore = 0;

// Engagement weight (40 points)
if (engagementRate >= 5) performanceScore += 40;
else if (engagementRate >= 3) performanceScore += 30;
else if (engagementRate >= 1) performanceScore += 20;
else performanceScore += 10;

// RSVP weight (30 points)
if (totalRSVPs >= 100) performanceScore += 30;
else if (totalRSVPs >= 50) performanceScore += 20;
else if (totalRSVPs >= 20) performanceScore += 10;

// Ticket sales weight (30 points)
if (socialAttribution >= 30) performanceScore += 30;
else if (socialAttribution >= 15) performanceScore += 20;
else if (socialAttribution >= 5) performanceScore += 10;

// Performance tier
let performanceTier = 'Poor';
if (performanceScore >= 80) performanceTier = 'Excellent';
else if (performanceScore >= 60) performanceTier = 'Good';
else if (performanceScore >= 40) performanceTier = 'Average';

return {
  ...eventData,

  // Facebook Event Stats
  fb_event_attending: fbEventStats.attending_count || 0,
  fb_event_interested: fbEventStats.interested_count || 0,
  fb_event_maybe: fbEventStats.maybe_count || 0,
  fb_event_total_rsvps: totalRSVPs,
  fb_event_rsvp_conversion: rsvpConversionRate,

  // Facebook Post Stats
  fb_post_impressions: impressions,
  fb_post_engaged_users: engagedUsers,
  fb_post_reactions: totalReactions,
  fb_post_shares: totalShares,
  fb_post_comments: totalComments,
  fb_post_total_engagement: totalEngagement,
  fb_post_engagement_rate: engagementRate,

  // Instagram Stats
  ig_impressions: igImpressions,
  ig_engagement: igEngagement,
  ig_saves: igSaves,

  // Cross-platform totals
  total_impressions: impressions + igImpressions,
  total_engagement: totalEngagement + igEngagement,

  // Ticket Sales
  tickets_sold: ticketsSold,
  ticket_revenue: revenue,
  avg_ticket_price: avgTicketPrice,
  social_attribution_percent: socialAttribution,
  social_revenue: socialRevenue,

  // ROI
  promotion_cost: promotionCost,
  roi_percent: roi,

  // Performance
  performance_score: performanceScore,
  performance_tier: performanceTier,

  // Meta
  analytics_completed_at: new Date().toISOString(),
  status: 'Analytics Complete'
};

