const performanceData = $node["Aggregate All Metrics"].json;
const aiResponse = $node["AI Performance Analysis"].json;

let aiInsights = {};
try {
  const content = aiResponse.choices?.[0]?.message?.content || aiResponse.message?.content || '{}';
  aiInsights = typeof content === 'string' ? JSON.parse(content) : content;
} catch (e) {
  aiInsights = { summary: 'Analysis pending', strengths: [], weaknesses: [], recommendations: [] };
}

return {
  ...performanceData,
  ai_summary: aiInsights.summary || '',
  ai_strengths: (aiInsights.strengths || []).join(' | '),
  ai_weaknesses: (aiInsights.weaknesses || []).join(' | '),
  ai_recommendations: (aiInsights.recommendations || []).join(' | '),
  ai_content_analysis: aiInsights.content_effectiveness || '',
  ai_audience_insights: aiInsights.audience_insights || ''
};

const event = $input.first().json;

// Store successful patterns for future AI content generation
if (event.performance_tier === 'Excellent' || event.performance_tier === 'Good') {
  const postedDate = new Date(event.posted_date);

  return {
    event_type: event.event_category || 'other',
    content_style: event.page_post_copy || event.description || '',
    posting_time: postedDate.getHours(),
    posting_day: postedDate.getDay(),
    engagement_rate: event.fb_post_engagement_rate || 0,
    performance_score: event.performance_score || 0,

    // Patterns to learn
    successful_opening: (event.page_post_copy || event.description || '').split('\n')[0],
    optimal_length: (event.page_post_copy || event.description || '').length,
    used_urgency: (event.page_post_copy || event.description || '').toLowerCase().includes('today') || 
                 (event.page_post_copy || event.description || '').toLowerCase().includes('now'),

    learned_at: new Date().toISOString()
  };
}

return null; // Skip low performers

